import{_ as e,a as t,b as l,c as o}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as r,o as i,c as n,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Other/magnet-transfer.md","filePath":"ur/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"ur/Other/magnet-transfer.md"};function p(c,a,m,h,u,g){return i(),n("div",null,[...a[0]||(a[0]=[d('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer magnet link سے files download کرتا ہے اور انہیں خودکار طور پر آپ کے منتخب کردہ cloud storage channel میں upload کرتا ہے۔</p><p>یہ anime episodes، videos، archives، اور ملتی جلتی files transfer کرنے کے لیے useful ہے۔ magnet link paste کریں، ImgBed background download task بناتا ہے۔ download مکمل ہونے کے بعد file ImgBed میں upload ہوتی ہے اور final link upload list میں دکھتا ہے۔</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="کہاں-استعمال-کریں" tabindex="-1">کہاں استعمال کریں <a class="header-anchor" href="#کہاں-استعمال-کریں" aria-label="Permalink to &quot;کہاں استعمال کریں&quot;">​</a></h2><p>magnet transfer entry homepage upload area میں ہے۔</p><p>magnet link input box میں paste کریں، <code>Transfer</code> منتخب کریں، پھر upload کریں۔</p><p><img src="'+t+'" alt="Upload anime" loading="lazy"></p><h2 id="first-use-سے-پہلے" tabindex="-1">First Use سے پہلے <a class="header-anchor" href="#first-use-سے-پہلے" aria-label="Permalink to &quot;First Use سے پہلے&quot;">​</a></h2><p>پہلے admin panel میں magnet transfer configure کریں۔</p><p>عموماً آپ کو چاہیے:</p><ol><li>download task چلانے کے لیے GitHub account۔</li><li>cloud upload channel، جیسے Google Drive یا OneDrive۔</li><li>target upload directory۔</li><li>task timeout۔</li></ol><p>settings تیار ہونے کے بعد homepage پر واپس جائیں اور magnet link paste کر کے transfer شروع کریں۔</p><h2 id="magnet-link-upload-کرنا" tabindex="-1">Magnet Link Upload کرنا <a class="header-anchor" href="#magnet-link-upload-کرنا" aria-label="Permalink to &quot;Magnet Link Upload کرنا&quot;">​</a></h2><ol><li>homepage upload box میں magnet link paste کریں۔</li><li>confirm کریں کہ mode <code>Transfer</code> پر set ہے۔</li><li>upload پر کلک کریں۔</li><li>ImgBed کے magnet task create کرنے کا انتظار کریں۔</li><li>task شروع ہونے کے بعد bottom-right corner میں floating <code>Magnet Tasks</code> panel سے progress چیک کریں۔</li></ol><p>download اور upload میں وقت لگ سکتا ہے۔ speed magnet resource، GitHub runtime environment، اور selected cloud storage channel پر depend کرتی ہے۔</p><p><img src="'+l+'" alt="Magnet downloading" loading="lazy"></p><h2 id="completion-کے-بعد" tabindex="-1">Completion کے بعد <a class="header-anchor" href="#completion-کے-بعد" aria-label="Permalink to &quot;Completion کے بعد&quot;">​</a></h2><p>task complete ہونے کے بعد upload list file name اور link دکھاتی ہے۔</p><p>videos video preview دکھاتے ہیں، images image preview دکھاتی ہیں، اور other files regular file icon دکھاتی ہیں۔</p><p><img src="'+o+'" alt="Downloaded video" loading="lazy"></p><p>آپ copy کر سکتے ہیں:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>direct file access</td></tr><tr><td>Markdown</td><td>Markdown posts یا notes</td></tr><tr><td>HTML</td><td>web page code</td></tr><tr><td>BBCode</td><td>BBCode support کرنے والے forums</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>bottom-right magnet task panel task count، task name، progress، اور final status دکھاتا ہے۔</p><p>Common states:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Waiting</td><td>task create ہو چکا ہے اور run ہونے کا انتظار کر رہا ہے۔</td></tr><tr><td>Downloading</td><td>magnet resource download ہو رہا ہے۔</td></tr><tr><td>Uploading</td><td>file download ہو چکی ہے اور cloud storage پر upload ہو رہی ہے۔</td></tr><tr><td>Completed</td><td>upload کامیاب ہے اور link copy کیا جا سکتا ہے۔</td></tr><tr><td>Failed</td><td>task کامیابی سے complete نہیں ہوا۔ message چیک کریں اور دوبارہ کوشش کریں۔</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>اگر magnet link میں multiple files ہوں تو ImgBed display کے لیے main completed file کو prioritize کرتا ہے۔</li><li>large files زیادہ وقت لیتی ہیں۔ page refresh کرنے سے پہلے task finish ہونے دیں۔</li><li>اگر magnet resource کے available peers نہ ہوں تو process بہت slow یا fail ہو سکتا ہے۔</li><li>cloud account quota ختم ہو، authorization expire ہو، یا upload directory غلط ہو تو task fail ہو سکتا ہے۔</li><li>upload complete ہونے کے بعد video preview چند seconds لے سکتی ہے۔</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="magnet-link-paste-کرنے-کے-بعد-کچھ-start-نہیں-ہوتا" tabindex="-1">Magnet Link Paste کرنے کے بعد کچھ Start نہیں ہوتا <a class="header-anchor" href="#magnet-link-paste-کرنے-کے-بعد-کچھ-start-نہیں-ہوتا" aria-label="Permalink to &quot;Magnet Link Paste کرنے کے بعد کچھ Start نہیں ہوتا&quot;">​</a></h3><p>confirm کریں کہ admin panel میں magnet transfer enabled ہے اور usable GitHub account / cloud channel selected ہے۔</p><h3 id="download-ہمیشہ-slow-ہے" tabindex="-1">Download ہمیشہ Slow ہے <a class="header-anchor" href="#download-ہمیشہ-slow-ہے" aria-label="Permalink to &quot;Download ہمیشہ Slow ہے&quot;">​</a></h3><p>magnet speed resource پر depend کرتی ہے۔ available peers نہ ہوں تو download بہت slow یا impossible ہو سکتا ہے۔</p><h3 id="upload-کے-بعد-preview-نہیں-آتا" tabindex="-1">Upload کے بعد Preview نہیں آتا <a class="header-anchor" href="#upload-کے-بعد-preview-نہیں-آتا" aria-label="Permalink to &quot;Upload کے بعد Preview نہیں آتا&quot;">​</a></h3><p>پہلے confirm کریں کہ file link کھلتا ہے۔ video files browser میں load ہونے کے لیے تھوڑا وقت لے سکتی ہیں، یا آپ link directly کھول سکتے ہیں۔</p><h3 id="task-fail-ہو-تو-کیا-چیک-کریں؟" tabindex="-1">Task Fail ہو تو کیا چیک کریں؟ <a class="header-anchor" href="#task-fail-ہو-تو-کیا-چیک-کریں؟" aria-label="Permalink to &quot;Task Fail ہو تو کیا چیک کریں؟&quot;">​</a></h3><p>magnet link valid ہے یا نہیں، cloud channel کام کر رہا ہے یا نہیں، اور upload directory درست ہے یا نہیں چیک کریں۔ پھر task دوبارہ submit کریں۔</p>',38)])])}const w=r(s,[["render",p]]);export{b as __pageData,w as default};
